<?php

namespace Database\Seeders;

use App\Models\SurveyQuestion;
use App\Models\SurveyTemplate;
use App\Models\User;
use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;

class TemplateQuestionSeeder extends Seeder
{
    public function run(): void
    {
        DB::transaction(function (): void {
            $user = User::query()->firstOrCreate(
                ['email' => 'admin@desa-wisata-bca.test'],
                [
                    'name' => 'Admin CSR',
                    'password' => 'password',
                ],
            );

            $template = SurveyTemplate::withTrashed()->firstOrNew([
                'title' => 'Instrumen Klasifikasi Desa/Kampung Wisata',
                'type' => 'village',
            ]);
            $shouldRestore = $template->exists && $template->trashed();

            $template->fill([
                'description' => 'Template pertanyaan hasil konversi dari template-question.pdf.',
                'status' => 'published',
                'created_by' => $user->id,
                'published_at' => now(),
            ]);
            $template->save();

            if ($shouldRestore) {
                $template->restore();
            }

            $template->questions()
                ->withTrashed()
                ->get()
                ->each(function (SurveyQuestion $question): void {
                    $question->options()->withTrashed()->forceDelete();
                    $question->forceDelete();
                });

            foreach ($this->rows() as $index => $row) {
                $question = $template->questions()->create([
                    'aspect' => $row['aspect'],
                    'code' => sprintf('Q%02d', $index + 1),
                    'question_text' => $row['question_text'],
                    'document_hint' => $row['document_hint'] ?: null,
                    'sort_order' => $index + 1,
                ]);

                foreach ($row['options'] as $optionIndex => $label) {
                    $question->options()->create([
                        'score' => $optionIndex + 1,
                        'label' => $label,
                        'sort_order' => $optionIndex + 1,
                    ]);
                }
            }
        });
    }

    /**
     * @return array<int, array{aspect: string, question_text: string, document_hint: string, options: array<int, string>}>
     */
    private function rows(): array
    {
        return collect(explode("\n", trim(self::SOURCE_ROWS)))
            ->map(function (string $line): array {
                [$aspect, $questionText, $documentHint, $options] = explode('|', $line);

                return [
                    'aspect' => $aspect,
                    'question_text' => $questionText,
                    'document_hint' => $documentHint,
                    'options' => explode('~', $options),
                ];
            })
            ->all();
    }

